```typescript
import { GmxSdk } from "@gmx-io/sdk";
import { createWalletClient, createPublicClient, http, parseUnits, parseEther } from "viem";
import { arbitrum } from "viem/chains";
import { privateKeyToAccount } from "viem/accounts";

const account = privateKeyToAccount("0x...");

const publicClient = createPublicClient({
  chain: arbitrum,
  transport: http("https://arb1.arbitrum.io/rpc"),
});

const walletClient = createWalletClient({
  account,
  chain: arbitrum,
  transport: http("https://arb1.arbitrum.io/rpc"),
});

const sdk = new GmxSdk({
  chainId: 42161,
  rpcUrl: "https://arb1.arbitrum.io/rpc",
  oracleUrl: "https://arbitrum-api.gmxinfra.io",
  subsquidUrl: "https://gmx.squids.live/gmx-synthetics-arbitrum:prod/api/graphql",
  account: account.address,
});

await sdk.setSigner(walletClient);
```

### 2. Fetch Market Data & Current ETH Price

```typescript
const { marketsInfoData, tokensData } = await sdk.markets.getMarketsInfo();

// Find ETH/USD perpetual market
const ethMarket = Object.values(marketsInfoData).find(
  (m) =>
    tokensData[m.indexTokenAddress]?.symbol === "WETH" &&
    !m.isSpotOnly
);

if (!ethMarket) throw new Error("ETH/USD market not found");

const wethAddress = ethMarket.longTokenAddress;
const usdcAddress = ethMarket.shortTokenAddress;
const marketAddress = ethMarket.marketTokenAddress;

// ETH price from market data (30-decimal precision)
const ethPriceUsd = ethMarket.indexToken.prices.maxPrice; // e.g. 3500 * 10^30
const PRICE_PRECISION = 10n ** 30n;
const USD_PRECISION = 10n ** 30n;
```

### 3. Calculate Position Parameters

```typescript
// $200 collateral, 5x leverage → $1000 position size
const COLLATERAL_USD = 200n;
const LEVERAGE = 5n;
const SIZE_USD = COLLATERAL_USD * LEVERAGE; // $1000

// Convert to GMX's 30-decimal USD precision
const sizeDeltaUsd = SIZE_USD * USD_PRECISION;           // $1000 in 30-dec
const collateralUsd = COLLATERAL_USD * USD_PRECISION;    // $200 in 30-dec

// --- Option A: USDC collateral (6 decimals) ---
