const currentEthPrice = ethPriceUsd / PRICE_PRECISION;   // human-readable
const acceptablePrice = ethPriceUsd * 101n / 100n;       // 1% above current
```

### 4. Calculate Execution Fee

```typescript
const gasLimits = await sdk.utils.getGasLimits();
const gasPrice = await sdk.utils.getGasPrice();

// Market increase order: no swaps, 3 oracle prices
const estimatedGasLimit = gasLimits.increaseOrder;
const oraclePriceCount = 3n;

let adjustedGasLimit = gasLimits.estimatedGasFeeBaseAmount;
adjustedGasLimit += gasLimits.estimatedGasFeePerOraclePrice * oraclePriceCount;
adjustedGasLimit += estimatedGasLimit * gasLimits.estimatedFeeMultiplierFactor / (10n ** 30n);

const executionFee = adjustedGasLimit * gasPrice;
// Typically ~0.0001 ETH (~$0.35 at $3500/ETH)
```

