    glvVaults: [
      { address: "0x528A5bac7E746C9A509A1f4F6dF58A03d44279F9", name: "GLV [WETH-USDC]" },
      { address: "0xdF03EEd325b82bC1d4Db8b49c30ecc9E05104b96", name: "GLV [WBTC-USDC]" },
    ],
  },
  {
    name: "Avalanche",
    chainId: 43114,
    rpcUrl: "https://api.avax.network/ext/bc/C/rpc",
