    ],
  },
  {
    name: "Botanix",
    chainId: 3637,
    rpcUrl: "https://node.botanixlabs.dev",
    oracleUrl: "https://botanix-api.gmxinfra.io",
    subsquidUrl: "https://gmx.squids.live/gmx-synthetics-botanix:prod/api/graphql",
    nativeSymbol: "BTC",
    glvVaults: [],
  },
];

const ERC20_ABI = [
  { name: "balanceOf", type: "function", stateMutability: "view",
    inputs: [{ name: "account", type: "address" }],
    outputs: [{ name: "", type: "uint256" }] },
  { name: "decimals", type: "function", stateMutability: "view",
    inputs: [], outputs: [{ name: "", type: "uint8" }] },
  { name: "symbol", type: "function", stateMutability: "view",
    inputs: [], outputs: [{ name: "", type: "string" }] },
];

async function getChainPortfolio(chain) {
  const result = {
    chain: chain.name,
    gmPositions: [],
    glvPositions: [],
    errors: [],
  };

  try {
    const sdk = new GmxSdk({
      chainId: chain.chainId,
      rpcUrl: chain.rpcUrl,
      oracleUrl: chain.oracleUrl,
      subsquidUrl: chain.subsquidUrl,
      account: WALLET,
    });

    // Get markets info (includes pool values and GM token addresses)
    const { marketsInfoData, tokensData } = await sdk.markets.getMarketsInfo();

    const client = createPublicClient({ transport: http(chain.rpcUrl) });

    // Check GM token balances for all markets
    const markets = Object.values(marketsInfoData);

    const balanceChecks = await Promise.allSettled(
      markets.map(async (market) => {
        const gmAddr = market.marketTokenAddress;
        const [balance, decimals] = await Promise.all([
          client.readContract({ address: gmAddr, abi: ERC20_ABI, functionName: "balanceOf", args: [WALLET] }),
          client.readContract({ address: gmAddr, abi: ERC20_ABI, functionName: "decimals" }),
        ]);
        return { market, balance, decimals };
      })
    );

    for (const check of balanceChecks) {
      if (check.status !== "fulfilled") continue;
      const { market, balance, decimals } = check.value;
      if (balance === 0n) continue;

      const humanBalance = parseFloat(formatUnits(balance, decimals));

      // Calculate USD value: GM price = poolValue / totalSupply
      // poolValueMax is in 30-decimal USD
      let usdValue = null;
      try {
        const totalSupply = market.totalSupply ?? market.marketTokenTotalSupply;
        if (totalSupply && totalSupply > 0n && market.poolValueMax) {
          const poolValueUsd = parseFloat(formatUnits(market.poolValueMax, 30));
          const totalSupplyHuman = parseFloat(formatUnits(totalSupply, decimals));
          const gmPrice = poolValueUsd / totalSupplyHuman;
          usdValue = humanBalance * gmPrice;
        }
      } catch {}

      const indexToken = tokensData?.[market.indexTokenAddress];
      const longToken = tokensData?.[market.longTokenAddress];
      const shortToken = tokensData?.[market.shortTokenAddress];
      const indexSymbol = indexToken?.symbol ?? market.indexTokenAddress.slice(0, 8);
      const longSymbol = longToken?.symbol ?? "?";
      const shortSymbol = shortToken?.symbol ?? "?";
      const poolName = market.isSpotOnly
        ? `GM: ${longSymbol}/${shortSymbol} [SPOT]`
        : `GM: ${indexSymbol}/USD [${longSymbol}-${shortSymbol}]`;

      result.gmPositions.push({
        pool: poolName,
        marketTokenAddress: market.marketTokenAddress,
        balance: humanBalance,
        usdValue,
      });
    }

    // Check GLV vault balances
    for (const vault of chain.glvVaults) {
      try {
        const [balance, decimals] = await Promise.all([
          client.readContract({ address: vault.address, abi: ERC20_ABI, functionName: "balanceOf", args: [WALLET] }),
          client.readContract({ address: vault.address, abi: ERC20_ABI, functionName: "decimals" }),
        ]);
        if (balance > 0n) {
          result.glvPositions.push({
            vault: vault.name,
            address: vault.address,
            balance: parseFloat(formatUnits(balance, decimals)),
          });
        }
      } catch (e) {
        result.errors.push(`GLV ${vault.name}: ${e.message}`);
      }
    }

  } catch (e) {
    result.errors.push(`Chain error: ${e.message}`);
  }

  return result;
}

// Run all chains in parallel
const results = await Promise.all(CHAINS.map(getChainPortfolio));
return results;
