That said, let me check what's available and walk you through the execution. I'll assume **Arbitrum** and **WETH collateral** as defaults.

```typescript
import { GmxSdk } from "@gmx-io/sdk";
import { createWalletClient, http, parseEther } from "viem";
import { arbitrum } from "viem/chains";

const sdk = new GmxSdk({
  chainId: 42161,
  rpcUrl: "https://arb1.arbitrum.io/rpc",
  oracleUrl: "https://arbitrum-api.gmxinfra.io",
  subsquidUrl: "https://gmx.squids.live/gmx-synthetics-arbitrum:prod/api/graphql",
});

await sdk.setAccount(walletClient.account);

// 1. Get current ETH price and market info
const { marketsInfoData, tokensData } = await sdk.markets.getMarketsInfo();

const ethMarket = Object.values(marketsInfoData).find(
  (m) =>
    tokensData[m.indexTokenAddress]?.symbol === "WETH" &&
    !m.isSpotOnly
);

const ethPrice = tokensData[ethMarket.indexTokenAddress].prices.maxPrice;
console.log("ETH price:", ethPrice);

// 2. Define position parameters
const collateralAmount = parseEther("0.1");   // 0.1 ETH collateral
const leverage = 50n;
const collateralUsd = collateralAmount * ethPrice / (10n ** 18n);
const sizeDeltaUsd = collateralUsd * leverage;  // 50x

console.log(`Collateral: 0.1 ETH (~$${collateralUsd / 10n**30n})`);
console.log(`Position size: $${sizeDeltaUsd / 10n**30n}`);

// 3. Check available liquidity
const maxLongOI = ethMarket.maxOpenInterestLong;
const currentLongOI = ethMarket.longInterestUsd;
const availableLiquidity = maxLongOI - currentLongOI;

if (sizeDeltaUsd > availableLiquidity) {
  throw new Error(`Insufficient liquidity. Available: $${availableLiquidity / 10n**30n}`);
}

// 4. Get execution fee
const { fees } = await sdk.trade.getIncreasePositionFees({
  marketAddress: ethMarket.marketTokenAddress,
  collateralTokenAddress: ethMarket.longTokenAddress,  // WETH
  sizeDeltaUsd,
  isLong: true,
});

console.log("Position fee:", fees.positionFeeUsd);
console.log("Execution fee:", fees.executionFeeUsd);
