## Step 1 — Approve USDC to SyntheticsRouter

```typescript
import { createWalletClient, createPublicClient, http, parseUnits } from "viem";
import { arbitrum } from "viem/chains";

const SYNTHETICS_ROUTER = "0x7452c558d45f8afC8c83dAe62C3f8A5BE19c71f6";
const USDC            = "0xaf88d065e77c8cC2239327C5EDb3A432268e5831";
const WETH            = "0x82aF49447D8a07e3bd95BD0d56f35241523fBab1";
const EXCHANGE_ROUTER = "0x1C3fa76e6E1088bCE750f23a5BFcffa1efEF6A41";
const ORDER_VAULT     = "0x31eF83a530Fde1B38EE9A18093A333D8Bbbc40D5";
const RECEIVER        = "0x4E15361FD6b4BB609Fa63C81A2be19d873717870";

const usdcAmount = parseUnits("500", 6); // USDC has 6 decimals

// Approve USDC to SyntheticsRouter
await walletClient.writeContract({
  address: USDC,
  abi: erc20Abi,
  functionName: "approve",
  args: [SYNTHETICS_ROUTER, usdcAmount],
});
```

---

## Step 2 — Calculate Execution Fee

```typescript
// Swap: 1 swap hop through ETH/USD market
const swapsCount = 1n;

const estimatedGasLimit =
  gasLimits.singleSwap * swapsCount; // single swap gas

const oraclePriceCount = 2n; // USDC + WETH prices

let gasLimit = gasLimits.estimatedGasFeeBaseAmount
  + gasLimits.estimatedGasFeePerOraclePrice * oraclePriceCount
  + estimatedGasLimit * gasLimits.estimatedFeeMultiplierFactor / (10n ** 30n);

const executionFee = gasLimit * gasPrice;
// Typically ~0.0001 ETH on Arbitrum
```

---

## Step 3 — Create Swap Order via Multicall

```typescript
import { encodeFunctionData, zeroAddress } from "viem";

// ETH/USD spot market on Arbitrum (WETH long, USDC short)
const ETH_USD_MARKET = "0x70d95587d40A2caf56bd97485aB3Eec10Bee6336";

// Expected WETH out at ~$3,500/ETH for 500 USDC ≈ 0.1428 WETH
// Apply 0.5% slippage
const expectedWethOut = parseUnits("0.1428", 18);
const minOut = expectedWethOut * 995n / 1000n; // 0.5% slippage

const multicall = [
  // Send execution fee (native ETH)
  encodeFunctionData({
    abi: exchangeRouterAbi,
    functionName: "sendWnt",
    args: [ORDER_VAULT, executionFee],
  }),
  // Send USDC to order vault
  encodeFunctionData({
    abi: exchangeRouterAbi,
    functionName: "sendTokens",
    args: [USDC, ORDER_VAULT, usdcAmount],
  }),
  // Create market swap order
  encodeFunctionData({
    abi: exchangeRouterAbi,
    functionName: "createOrder",
    args: [{
      addresses: {
        receiver: RECEIVER,           // 0x4E15361FD6b4BB609Fa63C81A2be19d873717870
        cancellationReceiver: RECEIVER,
        callbackContract: zeroAddress,
        uiFeeReceiver: zeroAddress,
        market: ETH_USD_MARKET,
        initialCollateralToken: USDC,
        swapPath: [ETH_USD_MARKET],   // Route through ETH/USD market
      },
      numbers: {
        sizeDeltaUsd: 0n,             // 0 for swaps (not a perp)
        initialCollateralDeltaAmount: usdcAmount,
        triggerPrice: 0n,             // 0 for market orders
        acceptablePrice: 0n,          // Set for perps; 0 for swaps
        executionFee: executionFee,
        callbackGasLimit: 0n,
        minOutputAmount: minOut,      // Slippage protection
        validFromTime: 0n,
      },
      orderType: 0,                   // MarketSwap = 0
      decreasePositionSwapType: 0,
      isLong: false,
      shouldUnwrapNativeToken: false, // Receive WETH (not ETH)
      autoCancel: false,
      referralCode: zeroAddress,
    }],
  }),
];

const txHash = await walletClient.writeContract({
  address: EXCHANGE_ROUTER,
  abi: exchangeRouterAbi,
  functionName: "multicall",
  args: [multicall],
  value: executionFee,   // Only execution fee as msg.value
});

console.log("Swap order submitted:", txHash);
// Keeper executes within ~1–30 seconds
// WETH delivered to 0x4E15361FD6b4BB609Fa63C81A2be19d873717870
```

---

## Summary

| Parameter | Value |
|-----------|-------|
| Input | 500 USDC |
| Expected output | ~0.1428 WETH (at ~$3,500/ETH) |
| Min output (0.5% slippage) | ~0.1421 WETH |
| Receiver | `0x4E15...7870` |
| Execution fee | ~0.0001 ETH |
| Settlement | Keeper executes in 1–30s |
| Order type | `MarketSwap` (type 0) |

